// Hand-maintained declarations for the "@salla.sa/twilight-bundles/vite-plugins/demo" subpath.
// The package.json "exports" map resolves this subpath's types to exactly this file, but tsc's
// own emit mirrors the src/ tree (demo/server-side/index.d.ts) rather than the flattened
// dist/vite-plugins/demo.js layout vite builds — so this file is written by hand. Keep it in
// sync with the public surface of src/vite-plugins/demo/server-side/index.ts.
import type { Plugin } from 'vite';
import type { IncomingMessage, ServerResponse } from 'http';

export interface DemoPluginOptions {
    components?: string[];
    grid?: {
        columns?: string;
        gap?: string;
        minWidth?: string;
    };
    css?: string;
    js?: string;
    formbuilder?: {
        languages?: string[];
        defaultLanguage?: 'ar' | 'en' | string;
    };
}

export declare function sallaDemoPlugin(options?: DemoPluginOptions): Plugin;

export declare function handleTemplatesRequest(req: IncomingMessage, res: ServerResponse): Promise<void>;

export declare function buildPreSeedScript(components: any[]): string;

export interface GeneratePublicPreviewResult {
    name: string;
    files: string[];
}

/**
 * @deprecated The static public-preview generator was removed — previews are now rendered
 * on demand by the public-preview Worker at https://salla.design/preview/<package>/<template>
 * once the bundle is published to npm. This stub generates nothing and returns an empty result.
 */
export declare function generatePublicPreview(bundleDir: string): GeneratePublicPreviewResult[];

export interface DemoTemplateOptions {
    grid: {
        columns: string;
        gap: string;
        minWidth: string;
    };
    css: string;
    js: string;
    formbuilder: {
        languages: string[];
        defaultLanguage: 'ar' | 'en' | string;
    };
    twilightBundles: any;
    publicPreview?: {
        templates: { name: string; href: string; category: { name: string; icon: string } | null }[];
        currentName: string;
        previewSrc: string;
    };
    preSeedScript?: string;
    publicAssets?: { css: string; js: string };
}

export declare const DEMO_CATEGORIES: Array<{
    id: number;
    name: { ar: string; en: string };
    icon: string;
}>;

export declare function resolveCategoryIcon(categoryId: string | undefined): { name: string; icon: string } | null;

export declare function createDemoHTML(
    components: Array<{ name: string; path: string; url: string; schema: string; rawComponent: any; order: number }>,
    options: DemoTemplateOptions,
    mode?: 'shell' | 'preview' | 'public-shell' | 'public-preview'
): string;
